public class Main {
    public static void main(String[] args) {
        int target = 67; // Sabit hedef sayi (demo amacli)

        System.out.println("Sayi tahmin oyunu basladi! (1-100 arasi)");
        System.out.println("(Bu demo, onceden belirlenmis tahminlerle calisir)\n");

        int[] guesses = {50, 75, 62, 68, 65, 67};
        boolean found = false;

        for (int guess : guesses) {
            System.out.println("Tahmin: " + guess);

            if (guess == target) {
                System.out.println("Tebrikler! Dogru tahmin: " + target);
                found = true;
                break;
            } else if (guess < target) {
                System.out.println("Daha buyuk bir sayi dene.\n");
            } else {
                System.out.println("Daha kucuk bir sayi dene.\n");
            }
        }

        if (!found) {
            System.out.println("\nTahmin edilemedi. Dogru sayi: " + target);
        }

        System.out.println("\nToplam deneme sayisi: " + guesses.length);
    }
}
